    "active" => [
        ["algo" => 596, "uuid" => "9e7033", "name" => "groth16", "type" => "zk", "status" => "active", "title" => "Groth16", "description_md" => "Groth16 is the most widely deployed zkSNARK (Zero-Knowledge Succinct Non-interactive ARgument of Knowledge). Offers constant-size proofs (3 group elements) and extremely fast verification.\n\nGroth16 requires a trusted setup per circuit (Powers of Tau). Used in Zcash Sapling, Filecoin, and most early ZK blockchain applications. Proofs verify in ~2ms. The trusted setup generates toxic waste that must be discarded.", "mental_model" => "Most deployed zkSNARK -- Zcash Sapling, 3-element proof, constant-time verify, circuit-specific trusted setup.", "purpose" => ["zk proof for arbitrary circuits"], "good_for" => ["zcash sapling", "filecoin post proofs", "small proof size", "fast verification"], "avoid_for" => ["no trusted setup (stark/bulletproofs)", "circuit agility (plonk/halo2)"], "pros" => ["smallest proofs (3 group elements)", "fastest verification", "widely deployed", "zcash standard"], "cons" => ["circuit-specific trusted setup", "toxic waste risk", "no universal setup"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Pairing-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Zcash shielded transaction proof", "input" => ["witness" => "private transaction data", "circuit" => "zcash sapling"], "output" => ["proof" => "3 G1 elements (~128 bytes)"]], "flow" => ["compile circuit to R1CS", "trusted setup: CRS per circuit", "prove: groth16(witness, CRS)", "verify: 3 pairings"], "related" => ["plonk", "halo2", "pinocchio", "kzg-commitment"]],
        ["algo" => 597, "uuid" => "9b2470", "name" => "plonk", "type" => "zk", "status" => "active", "title" => "PLONK", "description_md" => "PLONK (Permutations over Lagrange-bases for Oecumenical Non-interactive arguments of Knowledge) is a universal zkSNARK with a single trusted setup reusable across circuits.\n\nPLONK's universal and updatable SRS means no per-circuit trusted setup. Used in Aztec, Dusk Network, Mina Protocol. TurboPlonk and UltraPlonk extend it with lookup tables.", "mental_model" => "Universal trusted setup zkSNARK -- one setup for all circuits, Aztec/Mina standard.", "purpose" => ["universal zk circuit proofs"], "good_for" => ["aztec protocol", "circuit agility", "universal trusted setup"], "avoid_for" => ["no trusted setup needed (stark)", "smallest proof (groth16)"], "pros" => ["universal setup", "updatable SRS", "turbo/ultra extensions", "widely adopted"], "cons" => ["pairing-based quantum-vulnerable", "larger proofs than groth16"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Pairing-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Aztec private transaction PLONK proof", "input" => ["witness" => "private tx", "circuit" => "aztec"], "output" => ["proof" => "plonk proof ~400 bytes"]], "flow" => ["circuit -> gates", "SRS (universal setup)", "prove with KZG commitments", "verify: O(1) pairings"], "related" => ["groth16", "halo2", "shplonk", "kzg-commitment"]],
        ["algo" => 598, "uuid" => "f0fc89", "name" => "marlin", "type" => "zk", "status" => "active", "title" => "Marlin", "description_md" => "Marlin is a universal zkSNARK with a universal and updatable SRS based on R1CS. Used as the basis for Aleo's Proof System (snarkVM).\n\nMarlin reduces to the sum-check protocol and polynomial commitments. Universal setup allows all R1CS circuits to share one CRS.", "mental_model" => "Universal R1CS zkSNARK -- Aleo snarkVM, universal setup, sum-check based.", "purpose" => ["universal r1cs zk proofs"], "good_for" => ["aleo network", "universal r1cs proofs", "updatable srs"], "avoid_for" => ["plonkish circuits (plonk better)", "no trusted setup (stark)"], "pros" => ["universal r1cs", "aleo standard", "updatable srs"], "cons" => ["pairing quantum-vulnerable", "less ecosystem than groth16/plonk"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Pairing-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Aleo program snarkVM proof", "input" => ["witness" => "private input", "constraint_system" => "r1cs"], "output" => ["proof" => "marlin proof"]], "flow" => ["r1cs -> polynomial representations", "universal SRS commit", "sum-check + kzg opening"], "related" => ["groth16", "plonk", "spartan"]],
        ["algo" => 599, "uuid" => "ca9a46", "name" => "halo2", "type" => "zk", "status" => "active", "title" => "Halo2", "description_md" => "Halo2 is a zkSNARK by the Zcash Foundation enabling recursive proof composition without a trusted setup (using IPA/inner product argument or KZG). Used in Zcash Orchard and Scroll zkEVM.\n\nHalo2 pioneered accumulation scheme for recursion -- proofs can verify other proofs without exponential blowup. Widely used in zkEVM (Scroll, Taiko), Zcash Orchard.", "mental_model" => "Recursive zkSNARK without trusted setup -- Zcash Orchard, Scroll zkEVM, IPA/KZG commitment.", "purpose" => ["recursive zk proofs"], "good_for" => ["zcash orchard", "scroll zkevm", "recursive snark composition", "zkevm"], "avoid_for" => ["simple circuits (groth16 faster verif)", "fully no setup (stark)"], "pros" => ["recursive composition", "no per-circuit trusted setup (IPA)", "zkevm standard", "zcash orchard"], "cons" => ["larger proofs than groth16", "complex circuit design"], "difficulty" => 4, "security" => 5, "quantum_impact" => "IPA: discrete log quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Scroll zkEVM block proof", "input" => ["evm_trace" => "block execution", "circuit" => "halo2 zkevm"], "output" => ["proof" => "recursive halo2 proof"]], "flow" => ["PLONKish circuit design", "accumulation scheme for recursion", "IPA or KZG polynomial commitment", "verify: folding + opening"], "related" => ["plonk", "groth16", "nova", "kzg-commitment", "ipa"]],
        ["algo" => 600, "uuid" => "4fea60", "name" => "plonky2", "type" => "zk", "status" => "active", "title" => "Plonky2", "description_md" => "Plonky2 is a recursive zkSNARK by Polygon Labs combining PLONK with FRI polynomial commitment (no trusted setup). Extremely fast recursion using Goldilocks field arithmetic.\n\nPlonky2 achieves the fastest recursive proof generation (< 1 second per recursive step on consumer hardware). Used in Polygon zkEVM and zkVM.", "mental_model" => "FRI-based recursive PLONK -- fastest recursion, Polygon zkEVM, Goldilocks field.", "purpose" => ["fast recursive zk proofs"], "good_for" => ["polygon zkevm", "fast recursive proofs", "no trusted setup recursion"], "avoid_for" => ["ethereum-native (use halo2 for scroll)", "simple circuits"], "pros" => ["fastest recursive proofs", "no trusted setup (fri)", "goldilocks field fast", "polygon standard"], "cons" => ["polygon-specific ecosystem", "large proof size for non-recursive"], "difficulty" => 4, "security" => 4, "quantum_impact" => "FRI hash-based; closer to PQ.", "post_quantum_status" => 3, "example" => ["scenario" => "Polygon zkEVM recursive block proof", "input" => ["block" => "evm block trace"], "output" => ["proof" => "plonky2 recursive proof"]], "flow" => ["plonkish circuit", "fri polynomial commitment", "recursive proof aggregation"], "related" => ["plonk", "fri", "stark", "halo2"]],
        ["algo" => 601, "uuid" => "c38316", "name" => "stark", "type" => "zk", "status" => "active", "title" => "STARK", "description_md" => "STARK (Scalable Transparent ARgument of Knowledge) is a ZK proof system with no trusted setup, using only hash functions (quantum-secure). Used in StarkWare (StarkEx, StarkNet), and Ethereum scaling.\n\nSTARKs are transparent (no trusted setup) and post-quantum (hash-based). Proof sizes are larger than SNARKs (~50-200 KB) but generation is faster. Cairo language compiles to STARK circuits. StarkEx processes billions in DeFi value.", "mental_model" => "Transparent hash-based ZK proof -- no trusted setup, PQ hash security, StarkWare/Cairo/StarkNet.", "purpose" => ["transparent pq-compatible zk proofs"], "good_for" => ["starkware starknet", "cairo language", "no trusted setup zk", "quantum-resistant zk"], "avoid_for" => ["smallest proof size (groth16)", "ethereum L1 verify (expensive)"], "pros" => ["no trusted setup", "post-quantum (hash-based)", "starkware standard", "fast generation"], "cons" => ["large proof size (50-200 KB)", "eth L1 verification expensive"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Hash-based; post-quantum.", "post_quantum_status" => 4, "example" => ["scenario" => "StarkNet transaction batch proof", "input" => ["tx_batch" => "1000 transactions", "cairo_program" => "starknet"], "output" => ["proof" => "stark proof ~100KB"]], "flow" => ["execution trace", "low-degree extension (reed-solomon)", "fri polynomial commitment", "air constraints"], "related" => ["fri", "plonky2", "cairo", "bulletproofs"]],
        ["algo" => 602, "uuid" => "bfd2b2", "name" => "bulletproofs", "type" => "zk", "status" => "active", "title" => "Bulletproofs", "description_md" => "Bulletproofs are short non-interactive ZK proofs without a trusted setup. Based on inner product arguments. Used in Monero RingCT, Mimblewimble, and confidential transaction protocols.\n\nBulletproofs range proofs prove a value is in range [0, 2^n] without revealing it. Monero uses Bulletproofs+ (improved) for RingCT. Verification is O(n) in the constraint size.", "mental_model" => "No-trusted-setup range proofs -- Monero RingCT, Mimblewimble, inner product argument.", "purpose" => ["range proofs without trusted setup"], "good_for" => ["monero ringct range proofs", "mimblewimble", "confidential transactions"], "avoid_for" => ["fast verification (groth16)", "arbitrary circuits (plonk)", "post-quantum (dlp-based)"], "pros" => ["no trusted setup", "small range proof size", "monero standard"], "cons" => ["O(n) verification", "dlp quantum-vulnerable", "slower than groth16"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Discrete log; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Monero RingCT range proof", "input" => ["value" => "private tx amount", "range" => "[0, 2^64]"], "output" => ["proof" => "range proof (bulletproofs+)"]], "flow" => ["commit value with Pedersen commitment", "bulletproofs range proof via inner product", "verify O(n)"], "related" => ["groth16", "ipa", "stark", "spartan"]],
        ["algo" => 603, "uuid" => "a640cf", "name" => "spartan", "type" => "zk", "status" => "active", "title" => "Spartan", "description_md" => "Spartan is a transparent zkSNARK (no trusted setup) based on sum-check protocol and multilinear extensions. Delivers efficient proofs for R1CS without a trusted setup.\n\nSpartan has the fastest prover among transparent SNARKs. Used as a building block in Nova folding schemes.", "mental_model" => "Transparent sum-check R1CS SNARK -- no trusted setup, fastest transparent prover.", "purpose" => ["transparent r1cs zk proofs"], "good_for" => ["transparent snark", "nova folding building block", "fast prover without setup"], "avoid_for" => ["small proof size (groth16)", "trusted setup ok (plonk faster verify)"], "pros" => ["no trusted setup", "fast prover", "r1cs native", "nova building block"], "cons" => ["larger proofs than groth16", "less deployed"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Hash + DL based; partially PQ.", "post_quantum_status" => 2, "example" => ["scenario" => "Spartan transparent R1CS proof", "input" => ["witness" => "r1cs witness", "statement" => "r1cs"], "output" => ["proof" => "spartan proof"]], "flow" => ["r1cs -> multilinear extensions", "sum-check protocol", "polynomial evaluation proofs"], "related" => ["marlin", "nova", "bulletproofs", "lasso"]],
        ["algo" => 604, "uuid" => "57b449", "name" => "sonic", "type" => "zk", "status" => "active", "title" => "Sonic", "description_md" => "Sonic is a universal updatable SNARKs scheme predating PLONK. First universal zkSNARK construction. Superseded in practice by PLONK but historically important.", "mental_model" => "First universal updatable SNARK -- historical precursor to PLONK.", "purpose" => ["universal updatable zksnark"], "good_for" => ["historical zk study", "universal snark history"], "avoid_for" => ["production (plonk/halo2 better)"], "pros" => ["first universal updatable srs", "historical significance"], "cons" => ["superseded by plonk", "slow helper"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Pairing quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Sonic universal SNARK proof", "input" => ["circuit" => "any"], "output" => ["proof" => "sonic proof"]], "flow" => ["universal srs", "sonic prove + helper"], "related" => ["plonk", "marlin", "groth16"]],
        ["algo" => 606, "uuid" => "6cc149", "name" => "kzg-commitment", "type" => "commitment", "status" => "active", "title" => "KZG Commitment", "description_md" => "KZG (Kate-Zaverucha-Goldberg) polynomial commitments allow committing to a polynomial and later proving evaluations at any point. Used in Ethereum danksharding (EIP-4844), PLONK, and most modern SNARKs.\n\nKZG commitments are O(1) -- the commitment is a single elliptic curve point and evaluation proofs are also a single point. EIP-4844 uses KZG for blob commitments in Ethereum.", "mental_model" => "O(1) polynomial commitment -- Ethereum EIP-4844 blobs, PLONK/halo2 building block.", "purpose" => ["polynomial commitment scheme"], "good_for" => ["ethereum eip-4844 blobs", "plonk/halo2 polynomial commits", "snark building block"], "avoid_for" => ["no trusted setup (fri)", "post-quantum (pairing-based)"], "pros" => ["O(1) commitment and proof", "ethereum danksharding standard", "plonk/halo2 building block"], "cons" => ["trusted setup required", "pairing quantum-vulnerable", "not post-quantum"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Pairing-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Ethereum EIP-4844 blob commitment", "input" => ["blob" => "128 KB data", "srs" => "trusted setup"], "output" => ["commitment" => "single G1 point"]], "flow" => ["commit: C = f(s)*G (trusted setup scalar s)", "open: prove f(z)=y with quotient poly", "verify: e(C - y*G, H) = e(pi, s*H - z*H)"], "related" => ["plonk", "halo2", "fri", "shplonk"]],
        ["algo" => 607, "uuid" => "a40525", "name" => "fri", "type" => "commitment", "status" => "active", "title" => "FRI", "description_md" => "FRI (Fast Reed-Solomon IOP of Proximity) is a polynomial commitment scheme using Merkle trees and hash functions -- no trusted setup, post-quantum compatible. Core building block of STARKs and Plonky2.\n\nFRI enables transparent polynomial commitments without trusted setups. Proof size is logarithmic. Used in STARKs (StarkWare), Plonky2 (Polygon), and DEEP-FRI.", "mental_model" => "Hash-based polynomial commitment -- STARK/Plonky2 core, no trusted setup, PQ-compatible.", "purpose" => ["transparent polynomial commitment"], "good_for" => ["stark building block", "plonky2 polynomial commits", "no trusted setup poly commit", "pq-compatible"], "avoid_for" => ["small proofs (kzg o(1))", "pairing-ok environments"], "pros" => ["no trusted setup", "hash-based pq-compatible", "stark/plonky2 standard", "logarithmic proof size"], "cons" => ["larger proofs than kzg", "slower verification than kzg"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Hash-based; post-quantum.", "post_quantum_status" => 4, "example" => ["scenario" => "STARK FRI polynomial proximity proof", "input" => ["polynomial" => "trace poly", "domain" => "coset"], "output" => ["proof" => "fri proof merkle path"]], "flow" => ["fold: halve polynomial degree each round", "commit: merkle tree each round", "query: consistency checks"], "related" => ["stark", "plonky2", "kzg-commitment", "stir", "whir"]],
        ["algo" => 608, "uuid" => "6abd4a", "name" => "ligero", "type" => "zk", "status" => "active", "title" => "Ligero", "description_md" => "Ligero is a hash-based zkSNARK using MPC-in-the-head techniques and error-correcting codes. Transparent (no trusted setup) and post-quantum compatible.\n\nLigero uses a matrix-based linear code commitment. Proof size is O(sqrt(n)) in the circuit size.", "mental_model" => "MPC-in-the-head hash-based ZK -- transparent, O(sqrt(n)) proofs.", "purpose" => ["hash-based mpc-in-the-head zk"], "good_for" => ["pq-compatible transparent zk", "no trusted setup"], "avoid_for" => ["small proofs (groth16)", "fast verify (kzg-based)"], "pros" => ["transparent no trusted setup", "pq-compatible hash-based", "mpc-in-the-head"], "cons" => ["o(sqrt(n)) proof size", "slower than kzg-based"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Hash-based; post-quantum.", "post_quantum_status" => 4, "example" => ["scenario" => "Ligero circuit proof", "input" => ["circuit" => "r1cs", "witness" => "private input"], "output" => ["proof" => "ligero proof"]], "flow" => ["encode witness as matrix", "mpc-in-the-head commitment", "linear-code based proof"], "related" => ["stark", "aurora", "brakedown"]],
        ["algo" => 609, "uuid" => "7580b3", "name" => "dory", "type" => "commitment", "status" => "active", "title" => "Dory", "description_md" => "Dory is a transparent polynomial commitment scheme based on bilinear groups that avoids the trusted setup of KZG while maintaining O(sqrt(n)) proof size. Used in Arkworks and various ZK frameworks.", "mental_model" => "Transparent bilinear group poly commitment -- no trusted setup alternative to KZG.", "purpose" => ["transparent polynomial commitment"], "good_for" => ["kzg alternative without trusted setup", "bilinear-group transparent commits"], "avoid_for" => ["post-quantum (bilinear group)", "smallest proofs (fri/kzg)"], "pros" => ["no trusted setup", "bilinear group based", "transparent"], "cons" => ["o(sqrt(n)) larger than kzg o(1)", "bilinear group quantum-vulnerable"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Bilinear group; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Dory transparent commitment", "input" => ["polynomial" => "f(x)", "point" => "z"], "output" => ["commitment" => "C", "proof" => "eval proof"]], "flow" => ["commit to matrix representation", "inner product argument via bilinear groups"], "related" => ["kzg-commitment", "ipa", "spartan"]],
        ["algo" => 611, "uuid" => "5f12dd", "name" => "gm17", "type" => "zk", "status" => "active", "title" => "GM17", "description_md" => "GM17 (Groth-Maller 2017) is an improved zkSNARK construction that removes some of the assumptions of Groth16 while maintaining similar proof sizes. Used in some early ZK applications.", "mental_model" => "Groth16 variant with weaker assumptions -- GM17 zkSNARK.", "purpose" => ["zksnark with relaxed assumptions"], "good_for" => ["groth16 variant applications"], "avoid_for" => ["production (groth16 more deployed)"], "pros" => ["weaker assumptions than groth16", "similar proof sizes"], "cons" => ["less deployed than groth16", "circuit-specific setup"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Pairing-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "GM17 zkSNARK proof", "input" => ["witness" => "private", "circuit" => "r1cs"], "output" => ["proof" => "gm17 proof"]], "flow" => ["r1cs -> CRS", "prove gm17", "verify pairings"], "related" => ["groth16", "ggpr", "pinocchio"]],
        ["algo" => 612, "uuid" => "1c8b3c", "name" => "tfhe", "type" => "he", "status" => "active", "title" => "TFHE", "description_md" => "TFHE (Fast Fully Homomorphic Encryption over the Torus) is the FHE scheme enabling fast gate-by-gate evaluation with bootstrapping in milliseconds.\n\nTFHE is the fastest FHE scheme for binary gate evaluation. Enables arbitrary computation on encrypted data. Basis of the TFHE-rs and Zama Concrete libraries.", "mental_model" => "Millisecond-gate FHE -- fastest binary FHE, TFHE-rs / Zama Concrete.", "purpose" => ["fully homomorphic encryption gate evaluation"], "good_for" => ["encrypted computation", "zama concrete/tfhe-rs", "privacy-preserving inference"], "avoid_for" => ["arithmetic-heavy (ckks/bfv better)", "unencrypted compute (massive overhead)"], "pros" => ["fastest gate fhe", "arbitrary computation", "zama standard"], "cons" => ["large ciphertext expansion", "high compute overhead", "binary gate model"], "difficulty" => 5, "security" => 5, "quantum_impact" => "LWE-based; post-quantum.", "post_quantum_status" => 5, "example" => ["scenario" => "Encrypted boolean circuit evaluation", "input" => ["encrypted_bits" => "lwe ciphertexts"], "output" => ["result" => "encrypted output"]], "flow" => ["encrypt bits as LWE", "evaluate gates with bootstrapping", "bootstrapping refreshes noise"], "related" => ["bgv", "ckks", "bfv", "dm-cggi"]],
