        ["algo" => 613, "uuid" => "5355da", "name" => "bgv", "type" => "he", "status" => "new", "title" => "BGV", "description_md" => "BGV (Brakerski-Gentry-Vaikuntanathan) is a leveled Fully Homomorphic Encryption scheme supporting packed integers and SIMD operations on ciphertexts. Standard for integer FHE.\n\nBGV supports batching many integers into one ciphertext (SIMD packing). Used in HElib (IBM), OpenFHE. Optimal for integer arithmetic FHE circuits.", "mental_model" => "Integer SIMD FHE -- BGV/HElib, packed integers, leveled depth.", "purpose" => ["leveled integer fhe"], "good_for" => ["integer arithmetic fhe", "helib simd packing", "openfhe bgv mode"], "avoid_for" => ["floating point (ckks)", "binary gates (tfhe)"], "pros" => ["simd integer packing", "helib standard", "leveled depth efficient"], "cons" => ["bootstrapping expensive", "integer only"], "difficulty" => 5, "security" => 5, "quantum_impact" => "LWE-based; post-quantum.", "post_quantum_status" => 5, "example" => ["scenario" => "BGV private database query", "input" => ["encrypted_ints" => "packed integer ciphertexts"], "output" => ["result" => "encrypted query result"]], "flow" => ["encode integers as packed polynomial slots", "arithmetic: add/mult mod level", "bootstrapping to refresh level"], "related" => ["ckks", "bfv", "tfhe", "gsw"]],
        ["algo" => 614, "uuid" => "de0e03", "name" => "ckks", "type" => "he", "status" => "new", "title" => "CKKS", "description_md" => "CKKS (Cheon-Kim-Kim-Song) is an approximate FHE scheme for real/complex number arithmetic. Enables machine learning on encrypted floating-point data with controlled precision loss.\n\nCKKS is the standard for privacy-preserving ML inference and encrypted statistics. Used in Microsoft SEAL, OpenFHE, HElib. CKKS accepts small approximation errors in exchange for efficient floating-point FHE.", "mental_model" => "Approximate floating-point FHE -- CKKS/SEAL, private ML inference, controlled precision loss.", "purpose" => ["approximate floating point fhe"], "good_for" => ["private ml inference", "microsoft seal", "encrypted statistics", "floating point fhe"], "avoid_for" => ["exact integer (bgv/bfv)", "binary gates (tfhe)"], "pros" => ["floating point fhe", "microsoft seal standard", "ml inference standard", "batched complex numbers"], "cons" => ["approximate errors", "not exact arithmetic", "bootstrapping expensive"], "difficulty" => 5, "security" => 5, "quantum_impact" => "RLWE-based; post-quantum.", "post_quantum_status" => 5, "example" => ["scenario" => "CKKS encrypted neural network inference", "input" => ["encrypted_activations" => "ckks ciphertexts"], "output" => ["prediction" => "encrypted (approx)"]], "flow" => ["encode reals into ckks polynomial", "homomorphic ops with scale management", "rescale to control precision"], "related" => ["bgv", "bfv", "tfhe"]],
        ["algo" => 615, "uuid" => "b0ae00", "name" => "bfv", "type" => "he", "status" => "new", "title" => "BFV", "description_md" => "BFV (Brakerski-Fan-Vercauteren) is an exact integer FHE scheme similar to BGV but uses a different noise management approach (plaintext modulus switching). Used in Microsoft SEAL.\n\nBFV and BGV are complementary: BFV is often preferred for simpler parameter selection. Microsoft SEAL supports both BFV and CKKS.", "mental_model" => "Exact integer FHE -- BFV/SEAL alternative to BGV, simpler parameters.", "purpose" => ["exact integer fhe"], "good_for" => ["microsoft seal bfv mode", "exact integer fhe", "simpler parameter selection than bgv"], "avoid_for" => ["floating point (ckks)", "binary gates (tfhe)"], "pros" => ["exact integer arithmetic", "seal standard", "simpler than bgv"], "cons" => ["bootstrapping expensive", "integer only"], "difficulty" => 5, "security" => 5, "quantum_impact" => "RLWE-based; post-quantum.", "post_quantum_status" => 5, "example" => ["scenario" => "BFV private set operations", "input" => ["encrypted_set" => "bfv packed integers"], "output" => ["result" => "encrypted set op"]], "flow" => ["encode as integer polynomial slots", "add/mult with noise growth", "modulus switch"], "related" => ["bgv", "ckks", "tfhe"]],
        ["algo" => 616, "uuid" => "ab7112", "name" => "gsw", "type" => "he", "status" => "new", "title" => "GSW", "description_md" => "GSW (Gentry-Sahai-Waters) is a FHE scheme based on approximate eigenvector encryption. Notable for its simple construction and being the theoretical basis for FHEW and TFHE.\n\nGSW directly inspired TFHE and DM-CGGI. Uses matrix encryption where the secret key is an approximate eigenvector.", "mental_model" => "Approximate eigenvector FHE -- theoretical basis for TFHE/FHEW.", "purpose" => ["theoretical fhe basis for tfhe"], "good_for" => ["fhe theory", "tfhe/fhew foundation understanding"], "avoid_for" => ["production (use tfhe/ckks/bgv)"], "pros" => ["simple theoretical construction", "basis for tfhe", "no bootstrapping key"], "cons" => ["not practical alone", "large ciphertext expansion"], "difficulty" => 5, "security" => 5, "quantum_impact" => "LWE-based; post-quantum.", "post_quantum_status" => 5, "example" => ["scenario" => "GSW gate evaluation", "input" => ["C_a" => "encrypted bit a", "C_b" => "encrypted bit b"], "output" => ["C_ab" => "encrypted NAND"]], "flow" => ["encrypt as matrix with eigenvalue property", "evaluate gate via matrix multiply"], "related" => ["tfhe", "dm-cggi", "bgv"]],
        ["algo" => 617, "uuid" => "784541", "name" => "dm-cggi", "type" => "he", "status" => "new", "title" => "DM/CGGI (FHEW)", "description_md" => "DM/CGGI (Ducas-Micciancio / Chillotti-Gama-Georgieva-Izabachene) are the FHE schemes behind FHEW and TFHE bootstrapping. CGGI is TFHE's bootstrapping algorithm.\n\nCGGI introduced fast programmable bootstrapping for TFHE -- bootstrapping became fast enough for practical FHE gate evaluation.", "mental_model" => "TFHE bootstrapping algorithm -- CGGI/FHEW, fast programmable bootstrapping.", "purpose" => ["tfhe fast bootstrapping"], "good_for" => ["tfhe bootstrapping implementation", "fhe gate refresh"], "avoid_for" => ["standalone (tfhe component)"], "pros" => ["fast programmable bootstrapping", "tfhe-rs standard", "programmable function eval"], "cons" => ["complex", "tfhe component only"], "difficulty" => 5, "security" => 5, "quantum_impact" => "LWE-based; post-quantum.", "post_quantum_status" => 5, "example" => ["scenario" => "TFHE gate bootstrapping", "input" => ["noisy_ciphertext" => "after gate"], "output" => ["refreshed" => "noise-reduced ciphertext"]], "flow" => ["cmux tree bootstrapping", "blind rotation + sample extraction"], "related" => ["tfhe", "gsw", "bgv"]],
        ["algo" => 618, "uuid" => "0ec6f6", "name" => "nova", "type" => "zk", "status" => "new", "title" => "Nova", "description_md" => "Nova is an incrementally verifiable computation (IVC) scheme using folding schemes. Allows proving repeated application of a function incrementally -- each step folds into a single proof.\n\nNova's folding scheme is more efficient than recursive SNARKs for IVC. Used in zkVM designs, Nexus zkVM, and step-based computation proofs.", "mental_model" => "Folding IVC -- incrementally verify repeated computation, Nexus/zkVM standard.", "purpose" => ["incremental verifiable computation"], "good_for" => ["zkvm step proofs", "ivc incremental computation", "nexus zk"], "avoid_for" => ["batch (stark/groth16)", "non-incremental circuits"], "pros" => ["efficient ivc", "no recursive snark overhead", "folding scheme", "nexus standard"], "cons" => ["large internal witnesses", "not succinct alone (compress with snark)"], "difficulty" => 4, "security" => 4, "quantum_impact" => "DL-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Nova zkVM 1000-step proof", "input" => ["program" => "vm steps", "initial_state" => "s0"], "output" => ["accumulator" => "nova folded proof"]], "flow" => ["each step: fold running instance with new step", "output: single relaxed R1CS instance", "compress with snark for succinctness"], "related" => ["supernova", "hypernova", "spartan", "halo2"]],
        ["algo" => 619, "uuid" => "838152", "name" => "supernova", "type" => "zk", "status" => "new", "title" => "SuperNova", "description_md" => "SuperNova extends Nova to support multiple circuits in IVC (non-uniform IVC). Allows different opcodes/functions at each step, enabling more practical zkVMs.\n\nSuperNova enables zkVMs where each instruction is a different circuit -- more realistic for actual instruction set architectures.", "mental_model" => "Multi-circuit IVC -- Nova extended for non-uniform zkVM opcodes.", "purpose" => ["non-uniform ivc multiple circuits"], "good_for" => ["zkvm non-uniform ivc", "multi-opcode zk execution"], "avoid_for" => ["uniform circuits (nova)"], "pros" => ["multi-circuit ivc", "realistic zkvm support", "non-uniform computation"], "cons" => ["more complex than nova", "large witness size"], "difficulty" => 5, "security" => 4, "quantum_impact" => "DL-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "SuperNova RISC-V opcode VM", "input" => ["opcodes" => "mixed add/mul/load", "state" => "vm state"], "output" => ["ivc" => "supernova folded proof"]], "flow" => ["select circuit per step opcode", "nova folding per step", "compress final"], "related" => ["nova", "hypernova", "jolt", "sp1"]],
        ["algo" => 620, "uuid" => "330b91", "name" => "hypernova", "type" => "zk", "status" => "new", "title" => "HyperNova", "description_md" => "HyperNova extends Nova with CCS (Customizable Constraint Systems), a generalization of R1CS and PlonkISH. Enables folding for more expressive constraint systems.\n\nHyperNova folds CCS instances -- supports R1CS, PlonkISH, and AIR constraints in a single folding scheme.", "mental_model" => "CCS folding -- generalizes Nova to PlonkISH/R1CS/AIR constraints.", "purpose" => ["ccs constraint folding"], "good_for" => ["ccs folding", "plonkish + r1cs unified folding"], "avoid_for" => ["simple r1cs (nova)"], "pros" => ["ccs generalization", "r1cs + plonkish + air", "flexible constraints"], "cons" => ["more complex than nova", "research stage"], "difficulty" => 5, "security" => 4, "quantum_impact" => "DL-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "HyperNova CCS folding", "input" => ["ccs_instance" => "plonkish circuit"], "output" => ["folded" => "hypernova accumulator"]], "flow" => ["ccs constraint encoding", "multifolding via sum-check", "compress"], "related" => ["nova", "supernova", "protostar", "spartan"]],
        ["algo" => 621, "uuid" => "b809fd", "name" => "protostar", "type" => "zk", "status" => "new", "title" => "ProtoStar", "description_md" => "ProtoStar is a non-uniform IVC scheme based on folding for PLONK circuits. Extends the folding paradigm to handle non-linear PLONK constraints efficiently.", "mental_model" => "PLONK folding scheme -- non-linear PLONK constraints in IVC.", "purpose" => ["plonk non-linear folding"], "good_for" => ["plonk-native ivc folding"], "avoid_for" => ["r1cs (nova/hypernova)"], "pros" => ["plonk non-linear support", "non-uniform ivc"], "cons" => ["research stage", "less deployed than nova"], "difficulty" => 5, "security" => 4, "quantum_impact" => "DL-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "ProtoStar PLONK IVC", "input" => ["plonk_circuit" => "non-linear"], "output" => ["folded" => "protostar accumulator"]], "flow" => ["plonk circuit as ivc step", "protostar folding"], "related" => ["nova", "hypernova", "plonk"]],
        ["algo" => 622, "uuid" => "379f5c", "name" => "shplonk", "type" => "commitment", "status" => "new", "title" => "ShPlonk", "description_md" => "ShPlonk (Shift PLONK) is an optimized KZG multi-point evaluation proof scheme that batches multiple polynomial openings into a single proof more efficiently than standard KZG.\n\nShPlonk is used in halo2 (Zcash/Scroll) and PLONK variants to reduce the number of pairings needed for polynomial evaluation proofs.", "mental_model" => "Batched KZG multi-opening -- halo2 poly evaluation optimization.", "purpose" => ["batched kzg polynomial openings"], "good_for" => ["halo2 poly openings", "plonk batched proofs"], "avoid_for" => ["simple single eval (kzg)"], "pros" => ["batched multi-point openings", "halo2 standard", "fewer pairings"], "cons" => ["pairing quantum-vulnerable", "kzg trusted setup required"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Pairing-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Halo2 ShPlonk batched opening", "input" => ["polys" => "f1..fn", "points" => "z1..zn"], "output" => ["proof" => "single batched opening proof"]], "flow" => ["combine poly evals via random challenge", "single quotient polynomial", "single pairing verify"], "related" => ["kzg-commitment", "halo2", "plonk"]],
        ["algo" => 623, "uuid" => "9c4844", "name" => "ipa", "type" => "commitment", "status" => "new", "title" => "IPA", "description_md" => "IPA (Inner Product Argument) is a polynomial commitment scheme based on discrete log -- no trusted setup, O(log n) proof size. Used in Bulletproofs and halo2 (without KZG).\n\nIPA provides polynomial commitments without trusted setup. Halo2 can use IPA instead of KZG for a fully transparent proof system.", "mental_model" => "Discrete log poly commitment -- no trusted setup, O(log n), halo2/bulletproofs.", "purpose" => ["no-setup polynomial commitment"], "good_for" => ["halo2 transparent mode", "bulletproofs commitment", "no trusted setup"], "avoid_for" => ["smallest proof (kzg o(1))", "post-quantum (dlp)"], "pros" => ["no trusted setup", "halo2/bulletproofs standard", "discrete log based"], "cons" => ["o(log n) proof size", "o(n) verify", "dlp quantum-vulnerable"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Discrete log; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Halo2 transparent IPA commitment", "input" => ["polynomial" => "f(x)", "basis" => "generators"], "output" => ["commitment" => "EC point", "proof" => "ipa proof"]], "flow" => ["pedersen commitment to polynomial", "recursive halving argument", "o(log n) rounds"], "related" => ["kzg-commitment", "bulletproofs", "halo2", "dory"]],
        ["algo" => 624, "uuid" => "d981e7", "name" => "brakedown", "type" => "commitment", "status" => "new", "title" => "Brakedown", "description_md" => "Brakedown is a hash-based polynomial commitment scheme with linear prover time and post-quantum security. Uses linear codes for commitment.\n\nBrakedown achieves O(n) prover time -- the fastest prover among polynomial commitment schemes. Post-quantum via hash functions.", "mental_model" => "O(n) linear prover hash commitment -- fastest prover, PQ-compatible.", "purpose" => ["linear-time hash polynomial commitment"], "good_for" => ["fastest prover poly commit", "pq-compatible commitment"], "avoid_for" => ["small proof size (kzg o(1))", "fast verify (kzg)"], "pros" => ["o(n) linear prover", "pq hash-based", "no trusted setup"], "cons" => ["o(sqrt(n)) proof size", "slower verification"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Hash-based; post-quantum.", "post_quantum_status" => 4, "example" => ["scenario" => "Brakedown fast proving", "input" => ["polynomial" => "large n"], "output" => ["commitment" => "hash commit", "proof" => "linear-code proof"]], "flow" => ["encode polynomial as matrix rows", "hash commitment to rows", "linear-code opening"], "related" => ["fri", "ligero", "orion"]],
        ["algo" => 625, "uuid" => "691c55", "name" => "orion", "type" => "commitment", "status" => "new", "title" => "Orion", "description_md" => "Orion is a hash-based zkSNARK with linear prover time and polylogarithmic proof size. Improves on Brakedown proof size while maintaining hash-based post-quantum security.", "mental_model" => "Linear prover polylog proof hash SNARK -- PQ Brakedown improvement.", "purpose" => ["linear prover polylog hash snark"], "good_for" => ["pq snark with fast prover", "improved brakedown proofs"], "avoid_for" => ["trusted setup ok (plonk/groth16)"], "pros" => ["linear prover time", "polylog proof size", "pq hash-based"], "cons" => ["research stage", "less deployed"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Hash-based; post-quantum.", "post_quantum_status" => 4, "example" => ["scenario" => "Orion hash SNARK proof", "input" => ["circuit" => "r1cs", "witness" => "private"], "output" => ["proof" => "polylog orion proof"]], "flow" => ["linear code commitment", "sum-check based proof", "polylog proof size"], "related" => ["brakedown", "spartan", "ligero"]],
        ["algo" => 626, "uuid" => "ec8505", "name" => "stir", "type" => "commitment", "status" => "new", "title" => "STIR", "description_md" => "STIR (Shift To Improve Rates) is an improved polynomial proximity test that reduces FRI proof size by using rate shifts. Smaller proofs than FRI while maintaining hash-based security.", "mental_model" => "Improved FRI with smaller proofs -- rate-shifted FRI optimization.", "purpose" => ["improved fri proof size"], "good_for" => ["smaller fri proofs", "stark proof size optimization"], "avoid_for" => ["established fri pipelines (stir requires changes)"], "pros" => ["smaller than fri proofs", "hash-based pq", "fri improvement"], "cons" => ["newer, less deployed", "prover more complex"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Hash-based; post-quantum.", "post_quantum_status" => 4, "example" => ["scenario" => "STIR compact FRI proof", "input" => ["polynomial" => "trace poly"], "output" => ["proof" => "stir proof < fri size"]], "flow" => ["rate-shifted proximity test", "fewer query rounds than fri"], "related" => ["fri", "whir", "stark"]],
        ["algo" => 627, "uuid" => "8f7cdf", "name" => "whir", "type" => "commitment", "status" => "new", "title" => "WHIR", "description_md" => "WHIR further improves on STIR for Reed-Solomon proximity testing, achieving even smaller proof sizes while maintaining hash-based transparent security.", "mental_model" => "STIR successor -- further FRI proof size reduction.", "purpose" => ["further improved fri proofs"], "good_for" => ["minimal fri-style proofs"], "avoid_for" => ["standard pipelines (stir/fri stable)"], "pros" => ["smallest fri-style proofs", "hash-based pq", "transparent"], "cons" => ["very new research", "limited deployment"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Hash-based; post-quantum.", "post_quantum_status" => 4, "example" => ["scenario" => "WHIR compact RS proximity proof", "input" => ["polynomial" => "f"], "output" => ["proof" => "minimal rs proof"]], "flow" => ["whir folding scheme", "reduced query complexity"], "related" => ["stir", "fri", "stark"]],
        ["algo" => 628, "uuid" => "c4ed79", "name" => "basefold", "type" => "commitment", "status" => "new", "title" => "BaseFold", "description_md" => "BaseFold is a multilinear polynomial commitment scheme that generalizes FRI to multilinear polynomials. Enables direct commitment to multilinear extensions used in sum-check based systems.", "mental_model" => "FRI generalized to multilinear polynomials -- sum-check native commitment.", "purpose" => ["multilinear polynomial commitment"], "good_for" => ["sum-check based snarks", "multilinear native commitments"], "avoid_for" => ["univariate (kzg/fri better)"], "pros" => ["multilinear native", "fri generalization", "hash-based"], "cons" => ["newer scheme", "less deployed"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Hash-based; post-quantum.", "post_quantum_status" => 4, "example" => ["scenario" => "BaseFold multilinear commitment", "input" => ["mle" => "multilinear extension"], "output" => ["commitment" => "basefold commit"]], "flow" => ["fold multilinear poly", "fri-like commitment per fold"], "related" => ["fri", "spartan", "gemini"]],
        ["algo" => 629, "uuid" => "6f9b12", "name" => "gemini", "type" => "commitment", "status" => "new", "title" => "Gemini", "description_md" => "Gemini is an elastic SNARK framework that unifies linear-time proving with polynomial commitments via a streaming approach. Allows committing to polynomials defined by streaming data.", "mental_model" => "Elastic streaming SNARK -- linear prover, multilinear/univariate unified.", "purpose" => ["elastic streaming polynomial proofs"], "good_for" => ["linear prover elastic proofs", "streaming data commitments"], "avoid_for" => ["standard batch (stark/groth16)"], "pros" => ["elastic memory-efficient", "linear prover", "streaming"], "cons" => ["complex", "research"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Depends on commitment choice.", "post_quantum_status" => 3, "example" => ["scenario" => "Gemini large circuit streaming proof", "input" => ["stream" => "large witness"], "output" => ["proof" => "gemini elastic proof"]], "flow" => ["stream witness in passes", "sumcheck + commit", "elastic linear prover"], "related" => ["spartan", "brakedown", "basefold"]],
        ["algo" => 630, "uuid" => "44cd5b", "name" => "latticefold", "type" => "zk", "status" => "new", "title" => "LatticeFold", "description_md" => "LatticeFold is a post-quantum folding scheme based on lattice assumptions (Module-SIS). Analogous to Nova but post-quantum secure.\n\nLatticeFold enables IVC-like folding without relying on discrete log -- the first folding scheme with post-quantum security.", "mental_model" => "Post-quantum folding scheme -- Nova equivalent on lattice assumptions.", "purpose" => ["pq folding scheme for ivc"], "good_for" => ["pq ivc folding", "nova alternative post-quantum"], "avoid_for" => ["classical (nova faster)"], "pros" => ["post-quantum folding", "module-sis based", "ivc capability"], "cons" => ["slower than nova", "large witnesses", "research stage"], "difficulty" => 5, "security" => 5, "quantum_impact" => "Lattice-based; post-quantum.", "post_quantum_status" => 4, "example" => ["scenario" => "LatticeFold PQ IVC step", "input" => ["step" => "computation step", "prev" => "accumulator"], "output" => ["folded" => "pq accumulator"]], "flow" => ["module-sis commitment", "lattice folding protocol", "compress with pq snark"], "related" => ["nova", "hypernova", "ml-kem"]],
        ["algo" => 631, "uuid" => "d8e2da", "name" => "jolt", "type" => "zk", "status" => "new", "title" => "Jolt", "description_md" => "Jolt is a zkVM using lookup arguments (Lasso) and sum-check for efficient RISC-V execution proofs. Fastest RISC-V zkVM prover using the Lasso lookup argument.\n\nJolt proves RISC-V execution by expressing instruction evaluation as lookup tables rather than circuits. Dramatically reduces circuit complexity.", "mental_model" => "Lasso lookup-based RISC-V zkVM -- fastest RISC-V prover via lookup tables.", "purpose" => ["risc-v zk execution proofs"], "good_for" => ["risc-v zkvm", "fastest zk prover risc-v", "lasso lookup arguments"], "avoid_for" => ["evm (use sp1/risc0 or scroll/polygon)", "non-risc-v"], "pros" => ["fastest risc-v zkvm prover", "lookup-based efficiency", "lasso standard", "risc-v native"], "cons" => ["risc-v only", "not evm"], "difficulty" => 4, "security" => 4, "quantum_impact" => "DL-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Jolt RISC-V program proof", "input" => ["program" => "rust -> risc-v", "input" => "private input"], "output" => ["proof" => "jolt proof of execution"]], "flow" => ["compile to risc-v", "execution trace -> lasso lookups", "sum-check proof"], "related" => ["lasso", "sp1", "nova", "spartan"]],
        ["algo" => 632, "uuid" => "8af7c3", "name" => "sp1", "type" => "zk", "status" => "new", "title" => "SP1", "description_md" => "SP1 is a zkVM by Succinct Labs that proves arbitrary Rust programs compiled to RISC-V using STARK/PLONK recursion. Used in Ethereum Layer 2 and cross-chain bridges.\n\nSP1 compiles Rust to RISC-V and generates ZK proofs. Used in Succinct SP1, deployed in ZK coprocessors and L2 proving.", "mental_model" => "Rust/RISC-V zkVM -- SP1 by Succinct, STARK-based, ZK coprocessor L2.", "purpose" => ["rust zk program proofs"], "good_for" => ["rust zk program proving", "l2 zk coprocessor", "cross-chain zk proofs"], "avoid_for" => ["evm-specific (scroll/polygon zkevm)"], "pros" => ["rust developer friendly", "risc-v based", "succinct labs standard", "stark recursive"], "cons" => ["prover cost", "not evm-native"], "difficulty" => 3, "security" => 4, "quantum_impact" => "STARK hash-based (inner); pairing outer.", "post_quantum_status" => 2, "example" => ["scenario" => "SP1 Rust program ZK proof", "input" => ["rust_program" => "business logic", "input" => "private"], "output" => ["proof" => "sp1 proof"]], "flow" => ["compile rust -> risc-v", "execute + generate stark trace", "recursive stark aggregation", "optional snark compress"], "related" => ["jolt", "risc-zero", "nova", "stark"]],
        ["algo" => 633, "uuid" => "cfbbac", "name" => "lasso", "type" => "zk", "status" => "new", "title" => "Lasso", "description_md" => "Lasso is a lookup argument for zkVMs that efficiently handles very large lookup tables without needing to commit to the full table. Used in Jolt.\n\nLasso enables zkVMs to express CPU instructions as table lookups without committing to exponentially large tables.", "mental_model" => "Sparse lookup argument -- giant tables without full commitment, Jolt foundation.", "purpose" => ["efficient sparse lookup arguments"], "good_for" => ["jolt zkevm lookup tables", "cpu instruction lookup proofs"], "avoid_for" => ["small tables (plonkup/caulk simpler)"], "pros" => ["sparse table handling", "jolt standard", "no full table commit"], "cons" => ["specialized lookup", "jolt-specific"], "difficulty" => 4, "security" => 4, "quantum_impact" => "DL-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "RISC-V ADD instruction lookup proof", "input" => ["a" => "operand1", "b" => "operand2", "table" => "add table"], "output" => ["proof" => "lasso lookup"]], "flow" => ["decompose lookup into smaller sub-tables", "commit to evaluated sub-tables", "sum-check combining"], "related" => ["jolt", "spartan", "nova"]],
